import{_ as e,c as d,e as t,g as o}from"./index-Dy6EFjxH.js";const s=""+new URL("../images/about-side.svg",import.meta.url).href,c={},i={class:"page"};function b(l,a){return o(),d("div",i,[...a[0]||(a[0]=[t('<header class="page-head" data-v-a9b5e136><h1 data-v-a9b5e136>关于本站</h1><p class="sub" data-v-a9b5e136>国创 / 校创方言语料数字化展示（示例站）</p></header><div class="grid" data-v-a9b5e136><article class="card prose" data-v-a9b5e136><h2 data-v-a9b5e136>项目说明</h2><p data-v-a9b5e136> 本站从零使用 <strong data-v-a9b5e136>Vite + Vue 3</strong> 构建，与旧版工程相互独立，目录为仓库内 <code data-v-a9b5e136>corpus-web/</code>。 页面包含<strong data-v-a9b5e136>首页图文</strong>、<strong data-v-a9b5e136>语料分页</strong>、<strong data-v-a9b5e136>全文搜索</strong>与<strong data-v-a9b5e136>双轨音频</strong>（老派 / 新派）。 </p><p data-v-a9b5e136> 文本数据位于 <code data-v-a9b5e136>public/data/corpus.json</code>；配图为 <code data-v-a9b5e136>public/images/</code> 下 SVG； 录音放在 <code data-v-a9b5e136>public/audio/old_dialect</code> 与 <code data-v-a9b5e136>public/audio/new_dialect</code>，构建后随静态资源一并发布。 </p><h2 data-v-a9b5e136>技术要点</h2><ul data-v-a9b5e136><li data-v-a9b5e136>Hash 路由（<code data-v-a9b5e136>#/</code>），适配 GitHub Pages 子路径</li><li data-v-a9b5e136><code data-v-a9b5e136>base: &#39;./&#39;</code> 相对资源路径</li><li data-v-a9b5e136>语料拉取成功后写入 <code data-v-a9b5e136>localStorage</code> 作离线缓存</li><li data-v-a9b5e136>音频文件名自动尝试空格版与下划线版</li></ul></article><aside class="card aside" data-v-a9b5e136><img src="'+s+'" alt="线装书与声波装饰图" width="280" height="200" class="side-img" data-v-a9b5e136><h3 data-v-a9b5e136>替换资源</h3><ol data-v-a9b5e136><li data-v-a9b5e136>用完整语料覆盖 <code data-v-a9b5e136>corpus.json</code></li><li data-v-a9b5e136>按命名规则放入 mp3</li><li data-v-a9b5e136>运行 <code data-v-a9b5e136>npm run build</code></li></ol></aside></div>',2)])])}const r=e(c,[["render",b],["__scopeId","data-v-a9b5e136"]]);export{r as default};
